import torch
import torch.nn as nn
import torch.nn.functional as F


def _world_size():
    if torch.distributed.is_available() and torch.distributed.is_initialized():
        return torch.distributed.get_world_size()
    return 1


def _rank():
    if torch.distributed.is_available() and torch.distributed.is_initialized():
        return torch.distributed.get_rank()
    return 0


class _AllReduceSum(torch.autograd.Function):
    """Forward: sum across ranks (all_reduce). Backward: identity."""

    @staticmethod
    def forward(ctx, x):
        x = x.clone()
        if _world_size() > 1:
            torch.distributed.all_reduce(x)
        return x

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(torch.nn.Module):
    """Split the weight by columns (output dimension). Each rank holds a slice
    of the output features. The forward output is concatenated along the last
    dimension (all_gather). The bias is sharded like the output dimension.
    """

    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features

        world_size = _world_size()
        rank = _rank()

        assert out_features % world_size == 0, \
            "out_features must be divisible by world_size"
        self.out_features_per_partition = out_features // world_size

        # master_weight: [out_features, in_features]; split along dim 0 (rows in
        # PyTorch layout == output/column dimension of the math weight).
        weight_shard = master_weight.chunk(world_size, dim=0)[rank]
        self.weight = nn.Parameter(weight_shard.clone().detach())

        if bias:
            self.bias = nn.Parameter(
                torch.zeros(
                    self.out_features_per_partition,
                    dtype=self.weight.dtype,
                    device=self.weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        local_out = F.linear(input_, self.weight, self.bias)

        world_size = _world_size()
        if world_size == 1:
            return local_out

        rank = _rank()
        gathered = [torch.empty_like(local_out) for _ in range(world_size)]
        torch.distributed.all_gather(gathered, local_out.contiguous())
        # Keep the local shard attached to the autograd graph.
        gathered[rank] = local_out
        return torch.cat(gathered, dim=-1)


class RowParallelLinear(torch.nn.Module):
    """Split the weight by rows (input dimension). Each rank's forward receives
    only its pre-scattered slice of the input (already partitioned along the
    last dimension). Partial outputs are summed (all_reduce). Bias is full.
    """

    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features

        world_size = _world_size()
        rank = _rank()

        assert in_features % world_size == 0, \
            "in_features must be divisible by world_size"
        self.in_features_per_partition = in_features // world_size

        # master_weight: [out_features, in_features]; split along dim 1 (input
        # dimension == rows of the math weight).
        weight_shard = master_weight.chunk(world_size, dim=1)[rank]
        self.weight = nn.Parameter(weight_shard.clone().detach())

        if bias:
            self.bias = nn.Parameter(
                torch.zeros(
                    out_features,
                    dtype=self.weight.dtype,
                    device=self.weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        # input_ is already this rank's slice along the last (input) dimension.
        local_out = F.linear(input_, self.weight)
        output = _AllReduceSum.apply(local_out)
        if self.bias is not None:
            output = output + self.bias
        return output

